    return;
  const billingUrl = teamSlug ? getTeamBillingUrl(teamSlug) : "https://vercel.com/dashboard";
  void (0, import_open2.default)(billingUrl).catch((err) => {
    output_manager_default.debug(`Failed to open browser: ${err}`);
  });
