// src/util/firewall/build-action.ts
function buildActionFromFlags(flags, actionType) {
  const duration = flags["--duration"];
  if (duration && !VALID_DURATIONS2.includes(duration)) {
    return `Invalid duration "${duration}". Valid durations: ${VALID_DURATIONS2.join(", ")}`;
  }
  const action = {
    mitigate: {
      action: actionType,
      rateLimit: null,
      redirect: null,
      actionDuration: duration || null
    }
  };
  if (actionType === "rate_limit") {
    const algo = flags["--rate-limit-algo"] || "fixed_window";
    const window = flags["--rate-limit-window"];
    const requests = flags["--rate-limit-requests"];
    const keys = flags["--rate-limit-keys"] || ["ip"];
    if (!VALID_ALGORITHMS.includes(algo)) {
      return `Invalid rate limit algorithm "${algo}". Valid: ${VALID_ALGORITHMS.join(", ")}`;
    }
    if (!window || window < 10) {
      return "Rate limit --rate-limit-window is required (minimum 10 seconds).";
    }
    if (window > 3600) {
      return "Rate limit --rate-limit-window maximum is 3600 seconds (1 hour).";
    }
    if (!requests || requests < 1) {
      return "Rate limit --rate-limit-requests is required (minimum 1).";
    }
    if (requests > 1e7) {
      return "Rate limit --rate-limit-requests maximum is 10,000,000.";
    }
    const rlAction = flags["--rate-limit-action"] || "rate_limit";
    const validRlActions = ["log", "deny", "challenge", "rate_limit"];
    if (!validRlActions.includes(rlAction)) {
      return `Invalid rate limit action "${rlAction}". Valid: ${validRlActions.join(", ")}`;
    }
    action.mitigate.rateLimit = {
      algo,
      window,
      limit: requests,
      keys,
      action: rlAction
    };
  }
  if (actionType === "redirect") {
    const redirectUrl = flags["--redirect-url"];
    const permanent = !!flags["--redirect-permanent"];
    if (!redirectUrl) {
      return "Redirect action requires --redirect-url.";
    }
    if (!redirectUrl.startsWith("/") && !redirectUrl.startsWith("http://") && !redirectUrl.startsWith("https://")) {
      return "Redirect URL must start with /, http://, or https://";
    }
    action.mitigate.redirect = {
      location: redirectUrl,
      permanent
    };
  }
  return action;
}

